/**
 * Chế độ form document / voucher / master (full page).
 * Dùng chung với useFormFieldLock + VoucherFormToolbar.
 *
 * Per-form lock (user confirm): Linm.Development.Rules `field-readonly-lock-map.md`
 * · `{MFE}/docs/context/{module}/{feature}-readonly-lock.md`
 */
export enum FormMode {
  View = 'view',
  Edit = 'edit',
  Create = 'create',
}

export type FormFieldLockProps = { readOnly?: true; disabled?: true };

export interface FormFieldLockStyleClasses {
  viewReadOnlySection?: string;
  searchViewOnly?: string;
  embeddedSearch?: string;
  textareaReadOnly?: string;
}

export interface FormFieldLockInput {
  formMode: FormMode;
  /** Posted / Cancelled — khóa sửa dù đang edit (mức 9 ở Edit/Create: không khóa — `isVoucherFormFieldLocked`) */
  isStatusLocked?: boolean;
  styles?: FormFieldLockStyleClasses;
}

export interface FormFieldLockResult {
  formMode: FormMode;
  isViewMode: boolean;
  isEditing: boolean;
  isReadOnly: boolean;
  isStatusLocked: boolean;
  /** Wrapper section — chỉ view: màu input active */
  viewSectionClass: string | undefined;
  searchViewClass: string;
  fieldLockProps: FormFieldLockProps;
  staticFieldProps: FormFieldLockProps;
  searchDisabled: boolean;
  textareaClassName: string;
  textareaReadOnly: boolean | undefined;
  textareaDisabled: boolean;
  selectDisabled: boolean;
}

export {
  FORM_URL_MODE_PARAM,
  FORM_URL_MODE_EDIT,
  type FormNavigateEditIntent,
  isFormUrlEditMode,
  withFormEditModeSearch,
  withoutFormEditModeSearch,
  shouldStartFormInEditMode,
} from './formEditModeUrl';

export function initialFormMode(isNew: boolean, options?: { startInEditMode?: boolean }): FormMode {
  if (isNew) return FormMode.Create;
  return options?.startInEditMode ? FormMode.Edit : FormMode.View;
}

export function isEditingMode(mode: FormMode): boolean {
  return mode === FormMode.Edit || mode === FormMode.Create;
}

export function isViewMode(mode: FormMode): boolean {
  return mode === FormMode.View;
}

/**
 * Placeholder chỉ khi Create/Edit — View (và Posted/Cancelled) không hiển thị.
 * Rule: `erp-form-context.md` §8.14 · `voucher-form-toolbar.md`
 */
export function fieldPlaceholder(
  formMode: FormMode,
  text: string | undefined,
  options?: { isStatusLocked?: boolean },
): string | undefined {
  if (!isEditingMode(formMode)) return undefined;
  if (options?.isStatusLocked) return undefined;
  // Trim only — no fallback default (SearchInput used to replace undefined with default text)
  if (!text?.trim()) return undefined;
  return text.trim();
}

/** Route `/them` — luôn Create dù state formMode còn View (cùng component instance). */
export function effectiveFormMode(isNew: boolean, formMode: FormMode): FormMode {
  return isNew ? FormMode.Create : formMode;
}

/**
 * Quy tắc khóa field:
 * - View: readOnly + CSS active (không disabled xám)
 * - Create/Edit: field tĩnh disabled xám; field sửa được bình thường
 */
export function getFormFieldLock(input: FormFieldLockInput): FormFieldLockResult {
  const { formMode, isStatusLocked = false, styles = {} } = input;
  const view = isViewMode(formMode);
  const editing = isEditingMode(formMode);
  const readOnly = view || isStatusLocked;

  const embedded = styles.embeddedSearch ?? '';
  const searchViewClass = view && styles.searchViewOnly
    ? `${embedded} ${styles.searchViewOnly}`.trim()
    : embedded;

  const fieldViewProps: FormFieldLockProps = view ? { readOnly: true } : {};
  const fieldEditLockProps: FormFieldLockProps = !view && readOnly ? { disabled: true } : {};

  return {
    formMode,
    isViewMode: view,
    isEditing: editing,
    isReadOnly: readOnly,
    isStatusLocked,
    viewSectionClass: view ? styles.viewReadOnlySection : undefined,
    searchViewClass,
    fieldLockProps: view ? fieldViewProps : fieldEditLockProps,
    staticFieldProps: view ? { readOnly: true } : { disabled: true },
    searchDisabled: view ? false : readOnly,
    textareaClassName: view && styles.textareaReadOnly
      ? styles.textareaReadOnly
      : '',
    textareaReadOnly: view || undefined,
    textareaDisabled: !view && readOnly,
    selectDisabled: readOnly,
  };
}
